<?php
namespace App\Controllers;
use App\Core\Controller;use App\Models\Repository;use App\Helpers\{Auth,Csrf,Flash};
final class AdminController extends Controller {private function meta():array{return [
'generos'=>['title'=>'Géneros','fields'=>['nombre'=>'text','descripcion'=>'textarea']],
'artistas'=>['title'=>'Artistas','fields'=>['nombre'=>'text','biografia'=>'textarea','nacionalidad'=>'text','imagen_url'=>'file:image']],
'bandas'=>['title'=>'Bandas','fields'=>['nombre'=>'text','descripcion'=>'textarea','pais'=>'text','anio_formacion'=>'number','imagen_url'=>'file:image']],
'albumes'=>['title'=>'Álbumes','fields'=>['nombre'=>'text','artista_id'=>'select:artistas','banda_id'=>'select:bandas','genero_id'=>'select:generos','anio_lanzamiento'=>'number','portada_url'=>'file:image','descripcion'=>'textarea']],
'canciones'=>['title'=>'Canciones','fields'=>['nombre'=>'text','artista_id'=>'select:artistas','banda_id'=>'select:bandas','album_id'=>'select:albumes','genero_id'=>'select:generos','duracion'=>'text','audio_url'=>'file:audio','imagen_url'=>'file:image']],
'locales'=>['title'=>'Locales','fields'=>['nombre'=>'text','tipo'=>'text','direccion'=>'text','provincia'=>'text','capacidad'=>'number','telefono'=>'text','correo'=>'email','imagen_url'=>'file:image']],
'eventos'=>['title'=>'Eventos','fields'=>['nombre'=>'text','descripcion'=>'textarea','fecha'=>'date','hora'=>'time','local_id'=>'select:locales','precio'=>'number','capacidad'=>'number','imagen_url'=>'file:image']],
'planes'=>['title'=>'Planes Premium','fields'=>['nombre'=>'text','descripcion'=>'textarea','precio'=>'number','duracion_dias'=>'number']]
];} public function dashboard():void{Auth::requireAdmin();$db=(new Repository)->db();$stats=[];foreach(['usuarios','artistas','bandas','canciones','eventos','reproducciones','compras'] as $t)$stats[$t]=(int)$db->query("SELECT COUNT(*) FROM $t")->fetchColumn();$this->view('admin/dashboard',compact('stats'));} public function module(string $m,?int $edit=null):void{Auth::requireAdmin();$meta=$this->meta();if(!isset($meta[$m]))throw new \RuntimeException('Módulo inválido');$r=new Repository;$rows=$r->all($m);$record=$edit?$r->find($m,$edit):null;$options=[];foreach($meta[$m]['fields'] as $f=>$type)if(str_starts_with($type,'select:')){$t=substr($type,7);$options[$f]=$r->all($t,'nombre ASC');}$this->view('admin/module',['module'=>$m,'definition'=>$meta[$m],'rows'=>$rows,'record'=>$record,'options'=>$options]);} public function save(string $m):void{Auth::requireAdmin();Csrf::verify();$meta=$this->meta();if(!isset($meta[$m]))throw new \RuntimeException();$data=[];foreach($meta[$m]['fields'] as $f=>$type){if(str_starts_with($type,'file:')){$old=$_POST['old_'.$f]??null;$data[$f]=$this->upload($f,substr($type,5))??$old;}else{$v=trim((string)($_POST[$f]??''));$data[$f]=$v===''?null:$v;}}$id=isset($_POST['id'])&&$_POST['id']!==''?(int)$_POST['id']:null;(new Repository)->save($m,$data,$id);Flash::set('success','Registro guardado.');$this->redirect('/admin/'.$m);} private function upload(string $field,string $kind):?string{if(empty($_FILES[$field]['name'])||$_FILES[$field]['error']!==UPLOAD_ERR_OK)return null;$ext=strtolower(pathinfo($_FILES[$field]['name'],PATHINFO_EXTENSION));$ok=$kind==='image'?['jpg','jpeg','png','webp','gif']:['mp3','wav','ogg','m4a'];if(!in_array($ext,$ok,true))throw new \RuntimeException('Tipo de archivo no permitido.');$dir=dirname(__DIR__,2).'/public/uploads/'.$kind;if(!is_dir($dir))mkdir($dir,0775,true);$name=bin2hex(random_bytes(8)).'.'.$ext;move_uploaded_file($_FILES[$field]['tmp_name'],$dir.'/'.$name);$c=require dirname(__DIR__,2).'/config.php';return $c['base_url'].'/uploads/'.$kind.'/'.$name;} public function toggle(string $m,int $id):void{Auth::requireAdmin();Csrf::verify();(new Repository)->disable($m,$id);Flash::set('success','Estado actualizado.');$this->redirect('/admin/'.$m);} public function users(?int $edit=null):void{Auth::requireAdmin(false);$r=new Repository;$db=$r->db();$rows=$db->query("SELECT u.*,r.nombre rol FROM usuarios u JOIN roles r ON r.id=u.rol_id ORDER BY u.id DESC")->fetchAll();$roles=$r->all('roles','nombre');$record=$edit?$r->find('usuarios',$edit):null;$this->view('admin/users',compact('rows','roles','record'));} public function saveUser():void{Auth::requireAdmin(false);Csrf::verify();$id=(int)($_POST['id']??0);$data=['rol_id'=>(int)$_POST['rol_id'],'nombre'=>trim($_POST['nombre']),'correo'=>trim($_POST['correo']),'nacionalidad'=>trim($_POST['nacionalidad']),'tipo_usuario'=>$_POST['tipo_usuario'],'estado'=>(int)($_POST['estado']??1)];if(!empty($_POST['password']))$data['password']=password_hash($_POST['password'],PASSWORD_DEFAULT);(new Repository)->save('usuarios',$data,$id?:null);Flash::set('success','Usuario guardado.');$this->redirect('/admin/usuarios');}}
